import{_ as r,o as t,c as e,a2 as p}from"./chunks/framework.BWuWLRhz.js";const o="/images/the-primate-awards/11-1024x395.png",s="/images/the-primate-awards/2.png",n="/images/the-primate-awards/3.jpg",i="/images/the-primate-awards/4.jpg",h="/images/the-primate-awards/5.png",l="/images/the-primate-awards/6.png",m="/images/the-primate-awards/8.png",g="/images/the-primate-awards/9.png",A="/images/the-primate-awards/10.png",b="/images/the-primate-awards/11.png",c="/images/the-primate-awards/13.jpg",d="/images/the-primate-awards/14.jpeg",_="/images/the-primate-awards/15.png",f="/images/the-primate-awards/16.png",w="/images/the-primate-awards/17.png",u="/images/the-primate-awards/18.jpg",k="/images/the-primate-awards/19.jpg",q="/images/the-primate-awards/20.png",P="/images/the-primate-awards/21.png",y="/images/the-primate-awards/22.png",T="/images/the-primate-awards/25.png",x="/images/the-primate-awards/26.png",I="/images/the-primate-awards/27.png",F="/images/the-primate-awards/28.jpg",U="/images/the-primate-awards/29.jpg",j="/images/the-primate-awards/30.png",S="/images/the-primate-awards/31.png",M="/images/the-primate-awards/24.png",G="/images/the-primate-awards/33.png",Q="/images/the-primate-awards/pinit_fg_en_rect_gray_20.png",E=JSON.parse('{"title":"The Primate Awards","description":"","frontmatter":{"title":"The Primate Awards","titleZh":"灵长类摄影大奖","date":"2013-10-23T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/10/the-primate-awards.html","slug":"the-primate-awards"},"headers":[],"relativePath":"posts/the-primate-awards.md","filePath":"posts/the-primate-awards.md","lastUpdated":1782886257000}'),N={name:"posts/the-primate-awards.md"};function W(L,a,B,C,v,R){return t(),e("div",null,[...a[0]||(a[0]=[p('<h1 id="灵长类摄影大奖-·-the-primate-awards" tabindex="-1">灵长类摄影大奖 · The Primate Awards <a class="header-anchor" href="#灵长类摄影大奖-·-the-primate-awards" aria-label="Permalink to &quot;灵长类摄影大奖 · The Primate Awards&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/10/the-primate-awards.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/10/the-primate-awards.html</a> · 2013-10-23</p></blockquote><p>作为明星物种,人类很少去想想其他物种,连自己家族里的近亲都懒得搭理。他们几乎不花时间陪陪自己的直系亲属——类人猿 (Great Apes)——甚至连远亲(其他灵长类)的名字都叫不出来。<a href="http://www.intelligentdesign.org/" target="_blank" rel="noreferrer">有些人类</a>干脆直接否认自己跟这些兄弟姐妹表亲有任何关系。</p><p>但事实是,灵长目里还有 423 个其他物种,它们此时此刻都存在着,都在干着某些事,我们不可能永远无视它们。</p><p>为了让我们被遗忘的根源难得地曝光一下,我们要举办第一届年度灵长类大奖 (Primate Awards)。获奖者将根据本物种的饮食习惯,领取一串香蕉或者一只蚱蜢。</p><h1 id="灵长类大奖" tabindex="-1"><strong>灵长类大奖</strong> <a class="header-anchor" href="#灵长类大奖" aria-label="Permalink to &quot;**灵长类大奖**&quot;">​</a></h1><h3 id="最戏精灵长类" tabindex="-1"><strong>最戏精灵长类</strong> <a class="header-anchor" href="#最戏精灵长类" aria-label="Permalink to &quot;**最戏精灵长类**&quot;">​</a></h3><p><strong>获奖者:冕狐猴 (Sifaka)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/11.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="1"></a></p><p>尚不清楚冕狐猴是否知道自己并不是真的在舞台上,也并没有人真的在看他。但他对表演的渴望是无法遏制的。</p><h3 id="" tabindex="-1">** <a class="header-anchor" href="#" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最绝望的灵长类**</p><p><strong>获奖者:疣猴 (Colobus)</strong></p><p><a href="https://2.bp.blogspot.com/-L1N45oyzxnc/UmbTEZYauyI/AAAAAAAAF94/FxefFwLmo68/s1600/2.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>不管哪一天,不管哪个时刻,不管你在干什么,某个地方总有一只疣猴陷在彻底的绝望中。我们本以为获得这个奖项能让他开心一点,结果他反而更沮丧了。</p><h3 id="-1" tabindex="-1">** <a class="header-anchor" href="#-1" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>如果你给他一面镜子他会最震惊的灵长类**</p><p>**<br> 获奖者:山魈 (Mandrill)**</p><p>山魈以为自己长这样:</p><p><a href="https://2.bp.blogspot.com/-jYIeCM-2igk/UmbTN-SC8FI/AAAAAAAAF_M/n1ihws4xmFQ/s1600/3.jpg" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>他凭什么会觉得不是这样呢?这些都是正常的猴子颜色嘛,在他看来,他就是一只正常的猴子。</p><p>但他实际上长得像个小丑:</p><p><a href="https://1.bp.blogspot.com/-c9a-fE4LkOw/UmbTPhpDD7I/AAAAAAAAF_o/_Ulfwru9kbk/s1600/4.jpg" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>还没有谁有胆量跟他挑明这件事,这可能是最好的安排。</p><h3 id="-2" tabindex="-1">** <a class="header-anchor" href="#-2" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>带薪假最多的灵长类**</p><p>**<br> 获奖者:日本猕猴 (Japanese Macaque)**</p><p><a href="https://4.bp.blogspot.com/-W_l9_5LZAJs/UmbTQVkQoFI/AAAAAAAAGAA/M7wVoMPFA28/s1600/5.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>每次我看到这些家伙,他们都他妈的在温泉里。搞不懂他们是怎么谈下来这个待遇的,但他们把一切都安排得明明白白。</p><h3 id="-3" tabindex="-1">** <a class="header-anchor" href="#-3" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最能勉强蒙混成一个丑陋、蠢笨、举止怪异的人类的灵长类**</p><p>**<br> 获奖者:倭黑猩猩 (Bonobo)**</p><p><a href="https://2.bp.blogspot.com/-W6afCbm9TDQ/UmbTRGv9PcI/AAAAAAAAGAU/cbRFthQsMLg/s1600/6.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>倭黑猩猩<em>非常</em>接近于蠢版的人类。看这个哥们<a href="https://www.youtube.com/watch?v=EMbWDRzqNhc" target="_blank" rel="noreferrer">烤棉花糖</a>的样子,一副习以为常的德行。</p><h3 id="-4" tabindex="-1">** <a class="header-anchor" href="#-4" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>本来看起来会挺正常但一个荒唐特征毁掉一切的灵长类**</p><p>**<br> 并列冠军:长鼻猴和秃猴 (Proboscis Monkey and Uakari)**</p><p>先从长鼻猴 (proboscis monkey) 说起。</p><p>看看下面这些照片。挺正常的一只猴子,对吧?</p><p><a href="https://1.bp.blogspot.com/-7TDMzySsx8Q/UmbTQ-e2QzI/AAAAAAAAGAM/voSvG0GdiN0/s1600/8.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>并不是!</p><p><a href="https://3.bp.blogspot.com/-d4GTgwagniA/UmbTRaK4EqI/AAAAAAAAGAQ/GFiZwULcRh8/s1600/9.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>现在看看秃猴 (uakari)。在往下滚之前,先试着想象一下它正常的脑袋会长什么样。</p><p><a href="https://3.bp.blogspot.com/-jG-S9oV_dJ8/UmbS7gVkiaI/AAAAAAAAF8g/lJ_AkQ5rEPc/s1600/10.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><p>不管你想到了什么,我保证绝对不是一颗红色的小人类胎儿脑袋:</p><p><a href="https://3.bp.blogspot.com/-4K-_YoQShQ8/UmbS70-4IkI/AAAAAAAAF8k/PcmaNdypCPw/s1600/11.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>让人不安,对吧?看起来简直就像一个六年级小孩为了做万圣节贺卡,把一颗妖怪头 P 到了猴子照片上。</p><h3 id="-5" tabindex="-1">** <a class="header-anchor" href="#-5" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最欠揍灵长类**</p><hr><p>获奖者:猩猩宝宝****</p><p><a href="https://2.bp.blogspot.com/--wwRdOPdD1U/UmbS8qSX4gI/AAAAAAAAF9A/MeSJknBC4Yk/s1600/13.jpg" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>猩猩宝宝今年爆冷把奖抱回了家,让所有人都惊呆了,尤其是<a href="http://www.flickr.com/photos/100211469@N04/10438168693/in/photostream/lightbox/" target="_blank" rel="noreferrer">白颊长臂猿</a>,它拒绝对此发表评论。</p><h3 id="-6" tabindex="-1">** <a class="header-anchor" href="#-6" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最不想让它靠近你女儿的灵长类**</p><hr><p>获奖者:赤猴 (Patas Monkey)******</p><p><a href="https://4.bp.blogspot.com/-zWjW2Fq03LQ/UmbS81a3QqI/AAAAAAAAF80/q3HeN2vfo2Q/s1600/14.jpeg" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p>这种表情你根本不会指望在一个非人类脸上看到,这也让赤猴成为你最不希望出现在你女儿身边的灵长类。我们都宁愿不去了解赤猴脑子里那些阴暗角落里在想些什么。</p><h3 id="-7" tabindex="-1">** <a class="header-anchor" href="#-7" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最震惊灵长类**</p><hr><p>获奖者:大狐猴 (Indri)****</p><p><a href="https://4.bp.blogspot.com/-zLFIiWrEpTw/UmbS9OD0c5I/AAAAAAAAF9I/_luTIsCLQYc/s1600/15.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>你以为到现在大狐猴应该已经习惯这个世界的样子了,但它对一切依然感到震惊。</p><h3 id="-8" tabindex="-1">** <a class="header-anchor" href="#-8" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最具艺术家式痛苦的灵长类**</p><p><strong>获奖者:棉冠狨 (Cotton-Top Tamarin)</strong></p><p><a href="https://3.bp.blogspot.com/-v6tP6H3h5nA/UmbTNxlVxBI/AAAAAAAAF_c/8A0I4eI1h9A/s1600/16.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>以极其微弱的优势力压<a href="http://www.flickr.com/photos/100211469@N04/10438300614/in/photostream/lightbox/" target="_blank" rel="noreferrer">红脸蜘蛛猴</a>夺冠,棉冠狨是贝多芬级别的音乐天才,但根本没人注意到。</p><h3 id="-9" tabindex="-1">** <a class="header-anchor" href="#-9" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>脸最铺张浪费的灵长类**</p><p><strong>获奖者:阿尔法雄性猩猩</strong></p><p><a href="https://2.bp.blogspot.com/-gHZl3c7ryAs/UmbTALdci6I/AAAAAAAAF9o/jyFtLUtFW6U/s1600/17.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>天啊,红毛猩猩老大,你振作一点。这就是进化完全不受约束时会发生的事。对雄性红毛猩猩来说,脸越大,交配机会越大——现在整个雄性红毛猩猩群体已经在&quot;比脸大&quot;这条路上互相内卷到了荒谬的地步。</p><h3 id="-10" tabindex="-1">** <a class="header-anchor" href="#-10" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最灾难级灵长类**</p><p><strong>获奖者:这只特定的红毛猩猩老大</strong></p><p><a href="https://4.bp.blogspot.com/-nDNsoQx1Zi4/UmbS91C9EEI/AAAAAAAAF9U/IpJPKTiIVRI/s1600/18.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>作为今天唯一获得两项大奖的灵长类,这只特定的红毛猩猩老大简直就是彻头彻尾的灾难。</p><h3 id="-11" tabindex="-1">** <a class="header-anchor" href="#-11" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最像卡通角色的灵长类**</p><p><strong>获奖者:眼镜猴 (Tarsier)</strong></p><p>首先,让我们花点时间认可一下亚军——倒霉的懒猴 (slow loris)。</p><p><a href="https://1.bp.blogspot.com/-569DsVSeajs/UmbS-vE9ruI/AAAAAAAAF9g/mWywM1240kY/s1600/19.jpg" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p>进入冠军环节,我们有灵长类里的笑话物种——眼镜猴——</p><p><a href="https://2.bp.blogspot.com/-Tpfn8-MIQSc/UmbTCHAHwGI/AAAAAAAAF9w/0Ik8Djv338U/s1600/20.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p>这就是眼镜猴今天呈现给我们的整套形象,显然它觉得没必要装成一个正经生物。</p><h3 id="灵长类中的黑手党老大" tabindex="-1"><strong>灵长类中的黑手党老大</strong> <a class="header-anchor" href="#灵长类中的黑手党老大" aria-label="Permalink to &quot;**灵长类中的黑手党老大**&quot;">​</a></h3><p>大猩猩看起来是显而易见的选择,对吧?</p><p><a href="https://2.bp.blogspot.com/-leLltnj6yTs/UmbTGKHvjMI/AAAAAAAAF98/YM4gNA6CgjM/s1600/21.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a></p><p>结果发现,大猩猩只不过是<em>真正</em>黑手党老大的打手而已。</p><p><strong>获奖者:环尾狐猴 (Ring-Tailed Lemur)</strong></p><p><a href="https://1.bp.blogspot.com/-m_92tpjGuWY/UmbTKjTkXBI/AAAAAAAAF-k/TsoTecGXpZc/s1600/22.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p><p><a href="https://2.bp.blogspot.com/-mh_y9aX9Gek/UmbTKSFgxYI/AAAAAAAAF-Y/R1F1Q4tpARM/s1600/25.png" target="_blank" rel="noreferrer"><br></a></p><h3 id="父母与孩子颜色差异最尴尬奖" tabindex="-1">**父母与孩子颜色差异最尴尬奖 <a class="header-anchor" href="#父母与孩子颜色差异最尴尬奖" aria-label="Permalink to &quot;**父母与孩子颜色差异最尴尬奖&quot;">​</a></h3><p>**</p><p><strong>获奖者:银叶猴 (Silver Langur)</strong></p><p><img src="'+T+'" alt=""></p><p>每当你和一只银叶猴待在一起时,大家心照不宣的尴尬就是:她的孩子是一个亮橙色、脑袋圆滚滚的生物,明显跟她不是同一个物种。银叶猴拒绝承认这情况有任何奇怪之处,而我们其他人也都懂事地不去提。</p><h3 id="-12" tabindex="-1">** <a class="header-anchor" href="#-12" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最像爱尔兰神话角色的灵长类**</p><p>**获奖者:金狮狨 (Golden Lion Tamarin)<br> **</p><p><img src="'+x+'" alt=""><br> 所以现在我们有了精灵、矮妖精 (leprechaun),还有这只偶尔会朝你竖中指的橙色小地精猴。我本来想说拥有一只是我的终极幻想,但是……</p><h3 id="-13" tabindex="-1">** <a class="header-anchor" href="#-13" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>我比世界上任何东西都更想拥有的灵长类**</p><p><strong>获奖者:侏儒狨 (Pygmy Marmoset)</strong></p><p><img src="'+I+'" alt=""><br> 你他妈在逗我吗?当我发现这生物的照片时,我就一头栽进了维基百科的深渊,读到的事情包括:侏儒狨,又叫<em>手指猴</em>,A) 很聪明,即便按猴子的标准也算聪明,B) 能活12年以上,而且 C) 一跳能跳<em>4.9米</em>。</p><p>跟他一起生活会是梦想成真。想象一下一起吃晚饭,他坐在餐桌旁一张小小的高脚椅上。或者一起坐飞机,他系着一英寸长的安全带坐在你旁边的座位上。晚上你会把他塞进用 Altoid 薄荷糖铁盒做成的小床里。现在这是我唯一在乎的事。</p><h3 id="-14" tabindex="-1">** <a class="header-anchor" href="#-14" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最像梅丽尔·斯特里普的灵长类**</p><p><strong>获奖者:洛苏拉猴 (Lesula Monkey)</strong></p><p><img src="'+F+'" alt=""><br> 科学家们在 2007 年发现这种此前不为人知的猴子时惊呆了,它无论长相还是举止都跟梅丽尔·斯特里普 (Meryl Streep) 一模一样。</p><h3 id="-15" tabindex="-1">** <a class="header-anchor" href="#-15" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最像迈克尔·杰克逊的灵长类**</p><hr><p>获奖者:仰鼻猴 (Snub-Nosed Monkey)****</p><p><a href="https://4.bp.blogspot.com/-7Br59Dr-Yfk/UmbTMkTPEAI/AAAAAAAAF-0/7nVgebHsxXc/s1600/29.jpg" target="_blank" rel="noreferrer"><img src="'+U+'" alt=""></a></p><p>太诡异了,对吧?</p><h3 id="最像小布什的灵长类" tabindex="-1"><strong>最像小布什的灵长类</strong> <a class="header-anchor" href="#最像小布什的灵长类" aria-label="Permalink to &quot;**最像小布什的灵长类**&quot;">​</a></h3><p>**<br> 获奖者:猕猴 (Macaque)**</p><p><a href="https://2.bp.blogspot.com/-a3zRdXEB8S0/UmbTNqjQ_nI/AAAAAAAAF_I/GQx4CjGHUPU/s1600/30.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt=""></a></p><p>我们继续……</p><h3 id="-16" tabindex="-1">** <a class="header-anchor" href="#-16" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最令人难堪的灵长类**</p><p><strong>获奖者:白脸僧面猴 (White-Faced Saki)</strong></p><p><a href="https://3.bp.blogspot.com/-0RGa2YByYc4/UmbTOhzTKMI/AAAAAAAAF_s/IPBm-FuP2xg/s1600/31.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt=""></a><br> 白脸僧面猴是个不折不扣的废柴,所有灵长类都羞于承认他是自家亲戚。他的亲戚们也受够了他那张跟身体其他部分严重脱节的脸。就在大家以为不能更糟的时候,他决定留一撮山羊胡。</p><h3 id="最像迪士尼电影反派的灵长类" tabindex="-1"><strong>最像迪士尼电影反派的灵长类</strong> <a class="header-anchor" href="#最像迪士尼电影反派的灵长类" aria-label="Permalink to &quot;**最像迪士尼电影反派的灵长类**&quot;">​</a></h3><p><strong>获奖者:狮尾狒 (Gelada)</strong></p><p><a href="https://1.bp.blogspot.com/-3NGwoK638N0/UmbTJJ_HcVI/AAAAAAAAF-Q/Hlemmp0-LGc/s1600/24.png" target="_blank" rel="noreferrer"><img src="'+M+'" alt=""></a></p><p>这可没做过 PS——你还真有一位远房表亲长得就这么邪恶。仿佛他那张阴森至极的脸还不够似的,他还随时随地披着一件反派专用大衣。</p><h3 id="-17" tabindex="-1">** <a class="header-anchor" href="#-17" aria-label="Permalink to &quot;**&quot;">​</a></h3><p>最深陷无人理解之痛苦挣扎的灵长类**</p><p><strong>获奖者:指猴 (Aye-Aye)</strong></p><p><img src="'+G+'" alt=""><br> 没人知道指猴到底怎么了,但他确实正经历着某种鬼东西。这位灵长界的 <a href="http://photo.parismatch.com/media/photos2/3.-photos-culture/cinema/gollum/4306699-1-fre-FR/Gollum_galleryphoto_paysage_std.jpg" target="_blank" rel="noreferrer">咕噜</a> 也许有严重的偏执妄想问题,但也可能是他知道某个我们其他人都不知道的可怕真相。眼下嘛,可能还是离他远点比较好。</p><h2 id="如果你今天照镜子已经照够了-想笑话一下别人家族-来看看-wait-but-why-关于-兔子、虫子-和-鸟类-的文章。" tabindex="-1">如果你今天照镜子已经照够了,想笑话一下别人家族,来看看 Wait But Why 关于 <a href="https://waitbutwhy.com/2013/08/the-bunny-manifesto.html" target="_blank" rel="noreferrer">兔子</a>、<a href="https://waitbutwhy.com/2014/02/why-bugs-ruin-everything.html" target="_blank" rel="noreferrer">虫子</a> 和 <a href="https://waitbutwhy.com/2014/10/dark-secrets-bird-world.html" target="_blank" rel="noreferrer">鸟类</a> 的文章。 <a class="header-anchor" href="#如果你今天照镜子已经照够了-想笑话一下别人家族-来看看-wait-but-why-关于-兔子、虫子-和-鸟类-的文章。" aria-label="Permalink to &quot;如果你今天照镜子已经照够了,想笑话一下别人家族,来看看 Wait But Why 关于 [兔子](https://waitbutwhy.com/2013/08/the-bunny-manifesto.html)、[虫子](https://waitbutwhy.com/2014/02/why-bugs-ruin-everything.html) 和 [鸟类](https://waitbutwhy.com/2014/10/dark-secrets-bird-world.html) 的文章。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发送给你。</p><p>想要支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">推文</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/10/the-primate-awards.html&amp;description=The%20Primate%20Awards" target="_blank" rel="noreferrer"><img src="'+Q+'" alt=""></a></p>',140)])])}const Y=r(N,[["render",W]]);export{E as __pageData,Y as default};
